hooks.command:
node -e "
const fs = require('fs');
const path = require('path');
const keys = ['lighting','emp','noise','heaviness','tension','safety','siz','meteo','summary','conclusion','coding'];
const missing = [];
keys.forEach(k => {
  const tpl = path.join('public','templates', k+'-protocol.docx');
  if (!fs.existsSync(tpl)) missing.push(tpl);
});
if (missing.length) {
  console.error('HOOK WARNING: missing templates:', missing.join(', '));
} else {
  console.log('HOOK OK: all 11 templates present');
}
"
